class Solution:
    def minAnagramLength(self, s: str) -> int:
        from collections import Counter

        n = len(s)
        # The minimum possible length of t is at least 1 and at most n
        # We try all possible lengths of t that divide n
        for length in range(1, n + 1):
            if n % length != 0:
                continue
            # Check if all segments of length 'length' are anagrams
            target_count = Counter(s[:length])
            is_valid = True
            for i in range(length, n, length):
                segment = s[i:i + length]
                if Counter(segment) != target_count:
                    is_valid = False
                    break
            if is_valid:
                return length
        return n
